Script.script:
-- Create a simple UI for Sentry testing
function setupSentryTestUI()
    -- Create main container
    createLabel("SentryContainer", 0, 0, 300, 250, 0)
    setLabelStyleSheet("SentryContainer", [[
        background-color: #2c3e50;
        border: 2px solid #34495e;
        border-radius: 10px;
    ]])
    moveWindow("SentryContainer", 10, 50)

    -- Title
    createLabel("SentryTitle", 10, 10, 280, 30, 0)
    setLabelText("SentryTitle", "<center><b>SENTRY CRASH TEST</b></center>")
    setLabelStyleSheet("SentryTitle", [[
        color: #ecf0f1;
        font-size: 14pt;
        background-color: transparent;
    ]])
    setParent("SentryTitle", "SentryContainer")

    -- Info button
    createLabel("SentryInfoBtn", 10, 50, 280, 30, 0)
    setLabelText("SentryInfoBtn", "<center>Show Info</center>")
    setLabelStyleSheet("SentryInfoBtn", [[
        background-color: #3498db;
        color: white;
        border-radius: 5px;
        font-weight: bold;
    ]])
    setParent("SentryInfoBtn", "SentryContainer")
    setLabelClickCallback("SentryInfoBtn", function() send("sentry info") end)

    -- Test message button
    createLabel("SentryTestBtn", 10, 90, 280, 30, 0)
    setLabelText("SentryTestBtn", "<center>Send Test Message</center>")
    setLabelStyleSheet("SentryTestBtn", [[
        background-color: #27ae60;
        color: white;
        border-radius: 5px;
        font-weight: bold;
    ]])
    setParent("SentryTestBtn", "SentryContainer")
    setLabelClickCallback("SentryTestBtn", function() send("sentry test") end)

    -- Breadcrumb button
    createLabel("SentryBreadBtn", 10, 130, 280, 30, 0)
    setLabelText("SentryBreadBtn", "<center>Add Breadcrumb</center>")
    setLabelStyleSheet("SentryBreadBtn", [[
        background-color: #f39c12;
        color: white;
        border-radius: 5px;
        font-weight: bold;
    ]])
    setParent("SentryBreadBtn", "SentryContainer")
    setLabelClickCallback("SentryBreadBtn", function() send("sentry bread") end)

    -- Crash button (dangerous!)
    createLabel("SentryCrashBtn", 10, 170, 280, 30, 0)
    setLabelText("SentryCrashBtn", "<center>⚠ TRIGGER CRASH ⚠</center>")
    setLabelStyleSheet("SentryCrashBtn", [[
        background-color: #e74c3c;
        color: white;
        border-radius: 5px;
        font-weight: bold;
    ]])
    setParent("SentryCrashBtn", "SentryContainer")
    setLabelClickCallback("SentryCrashBtn", function() 
        if yesno("This will crash Mudlet! Are you sure?") then
            send("sentry crash2")
        end
    end)

    -- Warning text
    createLabel("SentryWarning", 10, 210, 280, 30, 0)
    setLabelText("SentryWarning", "<center><i>Crash tests will terminate Mudlet!</i></center>")
    setLabelStyleSheet("SentryWarning", [[
        color: #e74c3c;
        background-color: transparent;
        font-size: 9pt;
    ]])
    setParent("SentryWarning", "SentryContainer")

    print("Sentry Test UI created! Look for the panel on the left side.")
end

-- Auto-setup on load
registerAnonymousEventHandler("sysLoadEvent", function()
    tempTimer(1, function()
        setupSentryTestUI()
        print("================================")
        print("SENTRY CRASH REPORTING TEST LOADED")
        print("Type 'sentry info' for help")
        print("================================")
    end)
end)

-- Setup immediately if already connected
if getCurrentLine() then
    setupSentryTestUI()
end
